sys_element_mapping.value:
(function execute(inputs, outputs) {
	var actionResponse, actionID;
	
	outputs.output_message = '';
	
	var grEndpoint = inputs.endpoint_ref;
	var grActionPackage = inputs.action_package_ref;
	var expireSeconds = inputs.expire_seconds;
	
	var packageID = grActionPackage.getValue('package_id');
	var endpointSerial = grEndpoint.getValue('serial_number');
	
	var packageParams = transformParamInput(inputs.package_parameters);
	
	var tau = new x_taniu_tan_core.TaniumActionUtil();
	
	actionResponse = tau.createActionOnEndpointBySerial(
		packageID,
		endpointSerial,
		packageParams,
		expireSeconds || 86400
	);
	
	actionID = actionResponse.data.id;
	
	outputs.action_id = actionID;
	
	
	/**
	 * Transforms an array of package parameters into an object.
	 * From:
	 * [
	 *    {
	 *       param_key: "key1",
	 *       param_value: "value1"
	 *    },
	 *    {
	 *       param_key: "key2",
	 *       param_value: "value2"
	 *    }
	 * ]
	 *
	 * To:
	 * {
	 *   "key1": "value1",
	 *   "key2": "value2"
	 * }
	 *
	 * @param {[{}]} arrPackageParams  - array of package parameters
	 * @returns {{}}
	 */
	function transformParamInput(arrPackageParams) {
		var iParam, strKey, strValue;
		var statusMsg = '';
		var objTransformedParams = {};
		
		if (gs.nil(arrPackageParams) || !arrPackageParams || !arrPackageParams.length) {
			return objTransformedParams;
		}
		
		for (iParam = 0; iParam < arrPackageParams.length; iParam++) {
			strKey = arrPackageParams[iParam].param_key;
			strValue = arrPackageParams[iParam].param_value;
			
			//Trim whitespace from the key and value to ensure no weird issues I haven't thought of.
			strKey = strKey.trim();
			strValue = strValue.trim();
			
			//If the key is empty, skip it.
			//(This should not be possible, as Key is a required field, just covering my behind.)
			if (!strKey) {
				continue;
			}
			
			//If the key already exists in the transformed object, it's a duplicate -- warn & ignore.
			if (objTransformedParams.hasOwnProperty(strKey)) {
				statusMsg = 'Duplicate key found in package parameters: ' + strKey + '.\n' +
					'Original value: ' + objTransformedParams[strKey] + '\n' +
					'New value: ' + strValue + '\n' +
					'Original value will be used.';
				
				gs.warn(statusMsg);
				outputs.output_message += statusMsg + '\n\n';
				continue;
			}
			
			//If the value is empty, set it to an empty string to ensure no weird datatype issues.
			//(This shouldn't trigger on normally-falsy values like 0, since they'd come in as strings)
			if (!strValue) {
				strValue = '';
			}
			
			/*Add the key-value pair to the transformed object in the format:
				{
					"{key}": "{value}"
				}
			*/
			objTransformedParams[strKey] = strValue;
		}
		return objTransformedParams;
	}
	
})(inputs, outputs);

